insert into public.research_papers (title, abstract, authors, published_date, pdf_url, tags) values ('SamyamLM: A Satellite-Based Multimodal Data Labeling Platform for Indian Language AI Training', 'We introduce SamyamLM, a novel multimodal data labeling platform designed to facilitate high-quality training data generation for large language models (LLMs), vision-language models, and autonomous driving systems. Unlike existing platforms that rely on conventional crowd-sourcing pipelines, SamyamLM leverages satellite imagery and geospatial data streams as primary inputs, enabling scalable and cost-effective annotation of real-world scenarios across diverse Indian linguistic and geographic contexts. The platform supports Hindi and other Indian languages as first-class modalities, addressing a critical gap in the AI training ecosystem where Indic language data remains severely underrepresented. We describe the system architecture, data collection pipeline, labeling methodology, and quality assurance mechanisms. Benchmarks demonstrate that models trained on SamyamLM-curated datasets achieve competitive performance on Hindi visual question answering (VQA), satellite scene understanding, and autonomous driving tasks. SamyamLM aims to democratize AI development for the Indian subcontinent and position India as a key contributor to global foundation model training data infrastructure.', ARRAY['Shubham Patel'], '2026-04-03', '/__l5e/assets-v1/59eb94ea-30fe-4c57-97e9-ef916d404115/Samyalm_Paper.pdf', ARRAY['multimodal learning', 'data labeling', 'satellite imagery', 'Hindi NLP', 'Indian language AI', 'autonomous driving', 'foundation models', 'geospatial AI']);